			symbols = { "ᵐ", "ᶬ", "ⁿ̼d̼", "ᵐ̺b̺", "ⁿt", "ⁿd", "ⁿθ", "ⁿð", "ⁿs", "ⁿz", "ⁿʃ", "ⁿʒ", "ⁿɕ", "ⁿʑ", "ⁿr", "ⁿɬ", "ⁿɮ", "ⁿl", "ᶯ", "ᶮ", "ᵑ", "ᶰ" },
		},
		{
			name = "Pre-stopped consonant",
			symbols = { "ᵖ", "ᵇ", "ᵗ", "ᵈ", "𐞯", "𐞋", "ᶜ", "ᶡ", "ᵏ", "ᶢ", "𐞥", "𐞒", "𐞳" },
		},
		{
			name = "Post-stopped nasal",
			symbols = { "mᵇ", "nᵈ", "ɳ𐞋", "ɲᶡ", "ŋᶢ", "ɴ𐞒" },
		},
		{
			name = "Trilled affricate",
			symbols = { "ʳ", "𐞄", "𐞪", "tr̥", "dr" },
		},
	}
}

for k, group in pairs(rawData) do
	for _, v in ipairs(group) do
		local t = {
			name = v.name,
			symbol = v.symbols[1],
			article = v.article or v.name,
			audio = v.audio or ""
		}
		for _, s in ipairs(v.symbols) do
			data[k][s] = t
		end
	end
end

return { data = data, rawData = rawData }

