		{
			name = "Trilled affricate",
			symbols = { "ʳ", "𐞄", "𐞪", "tr̥", "dr" },
		},
	}
}

for k, group in pairs(rawData) do
	for _, v in ipairs(group) do
		local t = {
			name = v.name,
			symbol = v.symbols[1],
			article = v.article or v.name,
			audio = v.audio or ""
		}
		for _, s in ipairs(v.symbols) do
			data[k][s] = t
		end
	end
end

return { data = data, rawData = rawData }

